#' Retrieve linear B-cell data with ESM-1b features
#'
#' This function can be used to retrieve pre-computed LBCE datasets
#' extracted from the Immune Epitope DataBase (IEDB). The datasets
#' contain the features calculated using the ESM-1b embedder (
#' [https://github.com/facebookresearch/esm](https://github.com/facebookresearch/esm))
#'
#' @param taxonIDs A numeric or character vector with taxonomy IDs.
#' All LBCE entries related to organisms under the taxonomy IDs listed
#' will be returned.
#' @param tax_list taxonomy list (generated by [get_taxonomy()] or retrieved
#' using [get_basic_data()]).
#' @param ntries, number of times the routine will try to retrieve each dataset
#' before giving up
#' @param save_folder path to folder for saving the results.
#'
#' @return Returns `TRUE` invisibly upon successful completion.
#'
#' @author Felipe Campelo (\email{f.campelo@@aston.ac.uk})
#'
#' @export
#'

get_precomputed_datasets <- function(taxonIDs,
                                     tax_list,
                                     ntries = 3,
                                     save_folder = NULL){

  # ========================================================================== #
  # Sanity checks and initial definitions
  assertthat::assert_that(is.null(save_folder) | is.character(save_folder),
                          length(save_folder) <= 1,
                          is.character(taxonIDs) | is.numeric(taxonIDs),
                          length(taxonIDs) >= 1,
                          is.list(tax_list),
                          assertthat::is.count(ntries))

  baseURL <- "https://raw.githubusercontent.com/epitopes-dataset/ESM1b_IEDB_LBCE/main/data/"

  files <- utils::read.csv(url("https://raw.githubusercontent.com/epitopes-dataset/ESM1b_IEDB_LBCE/main/filelist.csv"),
                           quote = "")

  # Check save folder and create file names
  if(!is.null(save_folder)) {
    if(!dir.exists(save_folder)) dir.create(save_folder, recursive = TRUE)
  }

  # Function to extract the relevant organism IDs using the taxonomy data
  fextr <- function(x, tid){
    ul <- c(x$Taxonomy$UID, x$UID)
    if(any(tid %in% ul)) return(x$UID)
  }

  reslist <- vector("list", length = length(taxonIDs))

  # Try retrieving from github repo
  for (i in seq_along(taxonIDs)){
    target_org  <- unlist(sapply(tax_list,
                                 FUN = fextr,
                                 tid = taxonIDs[i]))

    fn <- paste0(baseURL, files$file[which(files$txid %in% target_org)])

    message("\nTaxonomy IDs under taxonID ",
            taxonIDs[i], "\nwith entries in the online repository:\n",
            paste(unique(files$txid[which(files$txid %in% target_org)]), collapse = ", "))

    tmplist <- vector("list", length(fn))
    for (j in seq_along(fn)){
      message("Retrieving data from ",
              strsplit(fn[j], split = "data/", fixed = TRUE)[[1]][2],
              " ", appendLF = FALSE)
      cc <- 0
      while (cc < ntries){
        errk <- FALSE
        tryCatch({
          tmplist[[j]] <- readRDS(url(fn[j]))
        },
        warning = function(c) {errk <<- TRUE},
        error   = function(c) {errk <<- TRUE},
        finally = NULL)

        if(errk){
          tmplist[[j]] <- NA
          cc <- cc + 1
          message(".", appendLF = FALSE)
          if(cc == ntries) message(" FAIL")
          Sys.sleep(.25)
        } else {
          message("OK")
          break
        }
      }
    }

    toRM <- which(sapply(tmplist, length) == 1)
    if(length(toRM) > 0) tmplist <- tmplist[-toRM]
    df  <- dplyr::bind_rows(lapply(tmplist, function(x)x$df))
    pep <- dplyr::bind_rows(lapply(tmplist, function(x)x$peptides))
    reslist[[i]] <- tmplist[[1]]
    reslist[[i]]$df <- df
    reslist[[i]]$peptides <- pep
  }

  if(!is.null(save_folder)){
    for (k in seq_along(reslist)){
      saveRDS(reslist[[k]], paste0(save_folder, "/txid", taxonIDs[k], "_dataset.rds"))
    }
  }

  invisible(TRUE)
}

